/**
 * Results Statistics Database - A-Level, IAL, IGCSE & GCSE
 *
 * Sources:
 * - CAIE A-Level: cambridgeinternational.org (2021-2026)
 * - CAIE IGCSE: cambridgeinternational.org (2021-2026)
 * - Edexcel IAL: qualifications.pearson.com (2025-2026)
 * - Edexcel UK A-Level: qualifications.pearson.com (2021-2025)
 * - Edexcel UK GCSE: qualifications.pearson.com (2021-2025)
 * - AQA A-Level: aqa.org.uk (2021-2025)
 * - AQA GCSE: aqa.org.uk (2021-2025)
 * - AQA L2 Cert: aqa.org.uk (2022-2025)
 * - OCR A-Level: ocr.org.uk (2021-2025)
 * - OCR GCSE: ocr.org.uk (2021-2025)
 *
 * All percentages are cumulative (achieving grade or higher).
 * Updated: 2025-07-01 from official grade statistics Excel
 */

export interface YearlyStats {
  year: number;
  series: "june" | "november" | "march" | "summer" | "january" | "autumn";
  aStarRate: number;
  aRate: number;
  bRate: number;
  cRate: number;
  dRate: number;
  eRate: number;
  entries?: number;
}

export interface SubjectStats {
  code: string;
  name: string;
  board: string;
  level: "A-Level" | "AS-Level" | "IGCSE" | "GCSE" | "L2 Cert" | "FSMQ";
  years: YearlyStats[];
}

function y(year: number, series: "june" | "november" | "march" | "summer" | "january" | "autumn", aStar: number, a: number, b: number, c: number, d: number, e: number, entries?: number): YearlyStats {
  return { year, series, aStarRate: aStar, aRate: a, bRate: b, cRate: c, dRate: d, eRate: e, entries };
}

function s(code: string, name: string, board: string, level: "A-Level" | "AS-Level" | "IGCSE" | "GCSE" | "L2 Cert" | "FSMQ", years: YearlyStats[]): SubjectStats {
  return { code, name, board, level, years };
}


