// ============================================================
// Export Helpers
// ============================================================

/** All subject stats combined (exported for compatibility) */
export const ALL_SUBJECT_STATS: SubjectStats[] = [
  ...AQA_A_LEVEL_SUBJECTS,
  ...AQA_GCSE_SUBJECTS,
  ...AQA_L2_CERT_SUBJECTS,
  ...CAIE_A_LEVEL_SUBJECTS,
  ...CAIE_IGCSE_SUBJECTS,
  ...EDEXCEL_A_LEVEL_SUBJECTS,
  ...EDEXCEL_IGCSE_SUBJECTS,
  ...EDEXCEL_UK_A_LEVEL_SUBJECTS,
  ...EDEXCEL_UK_GCSE_SUBJECTS,
  ...OCR_A_LEVEL_SUBJECTS,
  ...OCR_GCSE_SUBJECTS,
];

/** Get stats by subject code and board (merges all sources) */
export function getSubjectStats(code: string, board: string): SubjectStats | undefined {
  const matches = ALL_SUBJECT_STATS.filter(
    (s) => s.code === code && s.board === board
  );
  if (matches.length === 0) return undefined;
  if (matches.length === 1) return matches[0];
  const seen = new Set<string>();
  const mergedYears: YearlyStats[] = [];
  for (const m of matches) {
    for (const y of m.years) {
      const key = `${y.year}-${y.series}`;
      if (!seen.has(key)) {
        seen.add(key);
        mergedYears.push(y);
      }
    }
  }
  return { ...matches[0], years: mergedYears };
}

/** Get sorted subjects for a board and level */
export function getSortedSubjects(
  board: string,
  level: string
): { code: string; name: string }[] {
  const subjects = ALL_SUBJECT_STATS
    .filter((s) => s.board === board && s.level === level);
  const codeMap = new Map<string, string>();
  for (const s of subjects) {
    if (!codeMap.has(s.code)) codeMap.set(s.code, s.name);
  }
  const uniqueSubjects = Array.from(codeMap.entries()).map(([code, name]) => ({ code, name }));
  const prioritySubjects = [
    "Mathematics", "Further Mathematics", "Biology", "Chemistry", "Physics",
    "Economics", "Business", "Computer Science", "Psychology"
  ];
  const getPriority = (n: string) => {
    const idx = prioritySubjects.findIndex((p) => n.toLowerCase().includes(p.toLowerCase()));
    return idx === -1 ? 999 : idx;
  };
  return uniqueSubjects
    .sort((a, b) => {
      const pa = getPriority(a.name);
      const pb = getPriority(b.name);
      if (pa !== pb) return pa - pb;
      return a.code.localeCompare(b.code, undefined, { numeric: true });
    });
}

/** Get all boards that have data */
export function getAvailableBoards(): string[] {
  return [...new Set(ALL_SUBJECT_STATS.map((s) => s.board))];
}

/** Get all levels for a board (alias for compatibility) */
export function getLevelsForBoard(board: string): string[] {
  return [...new Set(ALL_SUBJECT_STATS.filter((s) => s.board === board).map((s) => s.level))];
}

/** Get available levels for a board (legacy name) */
export function getAvailableLevels(board: string): string[] {
  return getLevelsForBoard(board);
}

/** Get available subjects for a board and level (legacy name) */
export function getAvailableSubjects(board: string, level: string): { code: string; name: string }[] {
  return getSortedSubjects(board, level);
}
